const root = $input.all()[0]?.json ?? {};
const event = root.event ?? root;
const message = event.message ?? root.message ?? {};
const sender = event.sender ?? root.sender ?? {};
const senderId = sender.sender_id ?? sender.id ?? {};
const senderOpenId = firstString(senderId.open_id, sender.open_id, event.sender_id?.open_id, event.sender_id, root.sender_id?.open_id, root.sender_id);
const senderType = firstString(sender.sender_type, sender.type, event.sender_type, root.sender_type) || 'user';
const messageType = firstString(message.message_type, event.message_type, root.message_type);

if (senderType !== 'user' || messageType !== 'text') {
  return [];
}

function asArray(value) {
  return Array.isArray(value) ? value : [];
}

function firstString(...values) {
  for (const value of values) {
    if (value === undefined || value === null) continue;
    const text = String(value).trim();
    if (text) return text;
  }
  return '';
}

function parseContent(raw) {
  if (!raw) return { text: '', mentions: [] };
  if (typeof raw === 'object' && !Array.isArray(raw)) {
    return {
      ...raw,
      text: firstString(raw.text, raw.content),
      mentions: asArray(raw.mentions),
    };
  }

  const text = String(raw).trim();
  if (!text) return { text: '', mentions: [] };

  try {
    const parsed = JSON.parse(text);
    if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
      return {
        ...parsed,
        text: firstString(parsed.text, parsed.content, text),
        mentions: asArray(parsed.mentions),
      };
    }
  } catch (error) {
    // Some Lark triggers already provide plain text instead of JSON content.
  }

  return { text, mentions: [] };
}

function collectStrings(value, output = [], seen = new Set()) {
  if (value === undefined || value === null) return output;
  if (typeof value === 'string') {
    output.push(value);
    return output;
  }
  if (typeof value !== 'object') return output;
  if (seen.has(value)) return output;
  seen.add(value);
  if (Array.isArray(value)) {
    for (const item of value) collectStrings(item, output, seen);
    return output;
  }
  for (const item of Object.values(value)) collectStrings(item, output, seen);
  return output;
}

function uniqueMatches(strings, pattern) {
  const seen = new Set();
  const matches = [];
  for (const value of strings) {
    for (const match of String(value).matchAll(pattern)) {
      const id = match[0];
      if (!seen.has(id)) {
        seen.add(id);
        matches.push(id);
      }
    }
  }
  return matches;
}

function firstDifferent(currentId, ...values) {
  const current = String(currentId || '').trim();
  for (const value of values) {
    const text = firstString(value);
    if (text && text !== current) return text;
  }
  return '';
}

const content = parseContent(message.content ?? event.content ?? root.content ?? '');
let text = firstString(content.text, message.content_text, event.content_text, root.content_text);
if (!text) {
  return [];
}

const chatType = firstString(message.chat_type, message.chatType, event.chat_type, event.chatType, root.chat_type, root.chatType);
const chatId = firstString(message.chat_id, message.chatId, event.chat_id, event.chatId, root.chat_id, root.chatId, message.chat?.id, event.chat?.id, root.chat?.id);
const currentMessageId = firstString(message.message_id, message.messageId, event.message_id, event.messageId, root.message_id, root.messageId, message.id, event.id, root.id);
const messageId = currentMessageId;
const createTime = firstString(message.create_time, message.createTime, message.timestamp, event.create_time, event.createTime, event.timestamp, root.create_time, root.createTime, root.timestamp);
const stringsForIds = collectStrings({ root, event, message, content });
const omIds = uniqueMatches(stringsForIds, /\bom_[A-Za-z0-9_-]+\b/g).filter((id) => id !== currentMessageId);
const omtIds = uniqueMatches(stringsForIds, /\bomt_[A-Za-z0-9_-]+\b/g);
const threadId = firstString(
  message.thread_id,
  message.threadId,
  message.thread?.thread_id,
  message.thread?.id,
  event.thread_id,
  event.threadId,
  event.thread?.thread_id,
  event.thread?.id,
  root.thread_id,
  root.threadId,
  root.thread?.thread_id,
  root.thread?.id,
  omtIds[0]
);
const rootId = firstDifferent(
  currentMessageId,
  message.root_id,
  message.rootId,
  message.root?.message_id,
  message.root?.id,
  event.root_id,
  event.rootId,
  event.root?.message_id,
  event.root?.id,
  root.root_id,
  root.rootId,
  root.root?.message_id,
  root.root?.id
);
const parentId = firstDifferent(
  currentMessageId,
  message.parent_id,
  message.parentId,
  message.parent?.message_id,
  message.parent?.id,
  event.parent_id,
  event.parentId,
  event.parent?.message_id,
  event.parent?.id,
  root.parent_id,
  root.parentId,
  root.parent?.message_id,
  root.parent?.id
);
const referencedMessageId = firstDifferent(
  currentMessageId,
  message.referenced_message_id,
  message.referencedMessageId,
  message.reference?.message_id,
  message.reference?.id,
  message.reply_to?.message_id,
  message.replyTo?.messageId,
  message.quote?.message_id,
  message.quote?.id,
  event.referenced_message_id,
  event.referencedMessageId,
  event.reference?.message_id,
  event.reference?.id,
  event.reply_to?.message_id,
  event.replyTo?.messageId,
  event.quote?.message_id,
  event.quote?.id,
  root.referenced_message_id,
  root.referencedMessageId,
  root.reference?.message_id,
  root.reference?.id,
  root.reply_to?.message_id,
  root.replyTo?.messageId,
  root.quote?.message_id,
  root.quote?.id,
  parentId,
  rootId,
  omIds[0]
);
const hasReference = Boolean(referencedMessageId || parentId || rootId || threadId);
const isDirectChat = chatType === 'p2p';
const sessionKey = threadId && chatId
  ? `oar:chat:${chatId}:thread:${threadId}:user:${senderOpenId}`
  : (isDirectChat
    ? `oar:p2p:${senderOpenId}`
    : `oar:chat:${chatId}:user:${senderOpenId}`);
const contextHints = {
  hasReference,
  referencedMessageId,
  threadId,
  rootId,
  parentId,
  currentMessageId,
  chatId,
  chatType,
  createTime,
};

const rawMentions = [
  ...asArray(message.mentions),
  ...asArray(event.mentions),
  ...asArray(root.mentions),
  ...asArray(content.mentions),
];
const mentions = [];
const seenMentions = new Set();

function mentionIdInfo(mention) {
  const id = mention?.id ?? {};
  const openId = id.open_id ?? mention?.open_id ?? mention?.member_id ?? '';
  const userId = id.user_id ?? mention?.user_id ?? '';
  const unionId = id.union_id ?? mention?.union_id ?? '';
  if (openId) return { value: String(openId), type: 'open_id' };
  if (userId && typeof userId === 'string') return { value: userId, type: 'user_id' };
  if (unionId) return { value: String(unionId), type: 'union_id' };
  return { value: '', type: 'open_id' };
}

function mentionName(mention) {
  return firstString(
    mention?.name,
    mention?.display_name,
    mention?.member_name,
    mention?.nickname,
    mention?.name_default,
    mention?.i18n_name?.zh_cn,
    mention?.i18n_name?.en_us
  );
}

function mentionKey(mention) {
  return firstString(mention?.key, mention?.mention_key, mention?.token);
}

for (const mention of rawMentions) {
  if (!mention || typeof mention !== 'object' || Array.isArray(mention)) continue;
  const idInfo = mentionIdInfo(mention);
  const key = [idInfo.type, idInfo.value, mentionName(mention), mentionKey(mention)].join('|');
  if (seenMentions.has(key)) continue;
  seenMentions.add(key);
  mentions.push(mention);
}

function isAssistantMention(mention) {
  const name = mentionName(mention).toLowerCase();
  const mentionType = firstString(mention?.type, mention?.member_type, mention?.user_type).toLowerCase();
  return (
    name.includes('oar') ||
    name.includes('okr') ||
    name.includes('agent') ||
    name.includes('okr助手') ||
    mentionType.includes('bot')
  );
}

function escapeRegExp(value) {
  return String(value).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function stripAssistantMentions(source) {
  let result = source;
  for (const mention of mentions.filter(isAssistantMention)) {
    const key = mentionKey(mention);
    const name = mentionName(mention);
    if (key) result = result.replace(new RegExp(escapeRegExp(key), 'g'), ' ');
    if (name) result = result.replace(new RegExp('@?\\s*' + escapeRegExp(name), 'ig'), ' ');
  }
  return result.replace(/\s+/g, ' ').trim();
}

const commandMatch = text.match(/^\s*(?:\/oar|\/okr|@oar|@okr(?:\s+agent)?|@okr助手)\b/i);
const hasCommandPrefix = Boolean(commandMatch);
const mentionsAssistant = mentions.some(isAssistantMention);

if (!isDirectChat && !mentionsAssistant && !hasCommandPrefix) {
  return [];
}

if (mentionsAssistant) {
  text = stripAssistantMentions(text);
}

if (hasCommandPrefix) {
  const strippedText = text.replace(/^\s*(?:\/oar|\/okr|@oar|@okr(?:\s+agent)?|@okr助手)\s*/i, '').trim();
  text = strippedText || (/okr/i.test(commandMatch[0]) ? '查看我的 OKR' : '');
}

if (!text) {
  text = '查看我的 OKR';
}

const okrDomain = /(okr|目标|关键结果|本期|进度|对齐|复盘|objective|key result|kr)/i.test(text);
const wantsOkrRead = okrDomain && /(读|读取|查看|看看|看一下|列出|我的|当前|本期|进度|目标|关键结果|kr|objective|key result)/i.test(text);
const wantsBotDialog = /(问|询问|让|请|call|ask).*(机器人|bot)/i.test(text);
const targetMentionCandidate = wantsOkrRead ? mentions.find((mention) => !isAssistantMention(mention) && mentionIdInfo(mention).value) : null;
const explicitChatId = text.match(/\boc_[A-Za-z0-9_-]+\b/)?.[0] || '';
const asksGroupScope = /(这个群|本群|群里|群成员|大家|所有人|全部人|每个人|全员|团队|team|group)/i.test(text);
const wantsGroupOkrRead = wantsOkrRead && !targetMentionCandidate && (asksGroupScope || Boolean(explicitChatId));
const targetMention = wantsOkrRead && !wantsGroupOkrRead ? targetMentionCandidate : null;
const targetInfo = targetMention ? mentionIdInfo(targetMention) : { value: senderOpenId, type: 'open_id' };
const targetDisplayName = targetMention ? mentionName(targetMention) : '你';
const allowedChatId = explicitChatId || (!isDirectChat ? chatId : '');
const chatDisplayName = explicitChatId ? '指定群' : (!isDirectChat ? '当前群' : '');

return [
  {
    json: {
      text,
      intent: wantsGroupOkrRead ? 'read_group_okrs' : (wantsOkrRead ? 'read_okr' : (wantsBotDialog ? 'ask_bot' : 'chat')),
      chatId,
      chatType,
      messageId,
      senderOpenId,
      sessionKey,
      contextHints,
      targetUserId: targetInfo.value,
      targetUserIdType: targetInfo.type,
      targetDisplayName: targetDisplayName || '该用户',
      targetSource: targetMention ? 'mention' : 'self',
      allowedChatId,
      chatDisplayName,
    },
  },
];
